// Genera el mensaje de WhatsApp según el estado del pedido
// El backend envía: { order_number, new_status, delivery_type, total_amount, customer_phone, session_name, wpp_token }
const {
  order_number,
  new_status,
  delivery_type,
  total_amount,
  customer_phone,
  customer_name,
  session_name,
  wpp_token,
  mp_link,
  credit_applied,
  payment_policy,
} = $input.item.json;

const nombre = customer_name ? ` ${customer_name}` : '';

const mensajes = {
  pending_preparation: `✅ Tu pedido #${order_number} fue recibido${nombre}. ¡Ya estamos preparándolo!`,
  in_preparation: `👨‍🍳 Tu pedido #${order_number} está en preparación. ¡Ya casi está listo!`,
  to_dispatch: delivery_type === 'delivery'
    ? `🛵 Tu pedido #${order_number} salió para tu domicilio. ¡En camino!`
    : `🍕 Tu pedido #${order_number} está listo para retirar. ¡Te esperamos!`,
  in_delivery: `🚀 Tu pedido #${order_number} está muy cerca. ¡Ya llega!`,
  delivered: `🎉 ¡Tu pedido #${order_number} fue entregado${nombre}! Gracias por elegirnos. ¡Buen provecho!`,
  with_incident: `⚠️ Tuvimos un inconveniente con tu pedido #${order_number}. Estamos resolviéndolo y te avisamos pronto.`,
  cancelled_credit: `❌ Tu pedido #${order_number} fue cancelado. Tenés un crédito de $${parseFloat(total_amount || 0).toFixed(0)} para tu próximo pedido.`,
  cancelled_refund: `❌ Tu pedido #${order_number} fue cancelado. El reembolso será procesado en breve.`,
  cancelled_nocharge: `❌ Tu pedido #${order_number} fue cancelado. No se realizó ningún cobro.`,
  pending_payment_mp: mp_link ? `💳 Tu pedido #${order_number} está confirmado. Pagá por MercadoPago:\n${mp_link}` : null,
};

// Determinar qué mensaje usar
let mensaje = null;
if (new_status === 'cancelled') {
  if (payment_policy === 'credit') mensaje = mensajes.cancelled_credit;
  else if (payment_policy === 'refunded') mensaje = mensajes.cancelled_refund;
  else mensaje = mensajes.cancelled_nocharge;
} else if (new_status === 'pending_payment' && mp_link) {
  mensaje = mensajes.pending_payment_mp;
} else {
  mensaje = mensajes[new_status] || null;
}

if (!mensaje || !session_name || !customer_phone) {
  return [{ json: { skip: true, motivo: `Sin mensaje para estado ${new_status}` } }];
}

return [{ json: { mensaje, customer_phone, session_name, wpp_token, skip: false } }];
